<script>
  let currentValue = '0';
  let previousValue = '';
  let operator = null;
  let shouldResetCurrent = false;

  const currentEl = document.getElementById('current');
  const expressionEl = document.getElementById('expression');

  function updateDisplay() {
    currentEl.textContent = currentValue;
  }

  function appendDigit(digit) {
    if (shouldResetCurrent) {
      currentValue = digit;
      shouldResetCurrent = false;
    } else {
      currentValue = currentValue === '0' ? digit : currentValue + digit;
    }
    if (currentValue.length > 12) currentValue = currentValue.slice(0, 12);
    updateDisplay();
  }

  function appendDot() {
    if (shouldResetCurrent) {
      currentValue = '0.';
      shouldResetCurrent = false;
      updateDisplay();
      return;
    }
    if (!currentValue.includes('.')) {
      currentValue += '.';
      updateDisplay();
    }
  }

  function setOperator(op) {
    if (operator && !shouldResetCurrent) {
      calculate(true);
    }
    previousValue = currentValue;
    operator = op;
    shouldResetCurrent = true;
    const symbols = { '+': '+', '-': '−', '*': '×', '/': '÷' };
    expressionEl.textContent = previousValue + ' ' + symbols[op];
  }

  function calculate(chained = false) {
    if (!operator || previousValue === '') return;
    const prev = parseFloat(previousValue);
    const curr = parseFloat(currentValue);
    let result;
    switch (operator) {
      case '+': result = prev + curr; break;
      case '-': result = prev - curr; break;
      case '*': result = prev * curr; break;
      case '/':
        if (curr === 0) { currentValue = 'Error'; operator = null; previousValue = ''; expressionEl.textContent = ''; updateDisplay(); return; }
        result = prev / curr;
        break;
    }
    const symbols = { '+': '+', '-': '−', '*': '×', '/': '÷' };
    if (!chained) expressionEl.textContent = previousValue + ' ' + symbols[operator] + ' ' + currentValue + ' =';
    result = parseFloat(result.toPrecision(12));
    currentValue = String(result);
    if (currentValue.length > 12) currentValue = parseFloat(result.toPrecision(10)).toString();
    operator = null;
    previousValue = '';
    shouldResetCurrent = true;
    updateDisplay();
  }

  function clearAll() {
    currentValue = '0';
    previousValue = '';
    operator = null;
    shouldResetCurrent = false;
    expressionEl.textContent = '';
    updateDisplay();
  }

  function toggleSign() {
    if (currentValue === '0' || currentValue === 'Error') return;
    currentValue = currentValue.startsWith('-') ? currentValue.slice(1) : '-' + currentValue;
    updateDisplay();
  }

  function percent() {
    const val = parseFloat(currentValue);
    if (isNaN(val)) return;
    currentValue = String(val / 100);
    updateDisplay();
  }

  document.addEventListener('keydown', (e) => {
    if (e.key >= '0' && e.key <= '9') appendDigit(e.key);
    else if (e.key === '.') appendDot();
    else if (e.key === '+') setOperator('+');
    else if (e.key === '-') setOperator('-');
    else if (e.key === '*') setOperator('*');
    else if (e.key === '/') { e.preventDefault(); setOperator('/'); }
    else if (e.key === 'Enter' || e.key === '=') calculate();
    else if (e.key === 'Escape') clearAll();
    else if (e.key === 'Backspace') {
      if (currentValue.length > 1) currentValue = currentValue.slice(0, -1);
      else currentValue = '0';
      updateDisplay();
    }
  });
