  if (!nextPiece) return;
  const s = nextPiece.shape;
  const size = 16;
  const ox = Math.floor((80 - s[0].length * size) / 2);
  const oy = Math.floor((80 - s.length * size) / 2);
  for (let r = 0; r < s.length; r++)
    for (let c = 0; c < s[r].length; c++)
      if (s[r][c]) drawCell(c, r, COLORS[nextPiece.id], nCtx, size, ox, oy);
}

function spawn() {
  piece = nextPiece || randomPiece();
  nextPiece = randomPiece();
  drawNext();
  if (collides(piece)) {
    gameOver = true;
    cancelAnimationFrame(animId);
    const ov = document.getElementById('overlay');
    ov.innerHTML = '<h2>GAME OVER</h2><p>Score: ' + score + '</p><p style="margin-top:8px">Press any key to restart</p>';
    ov.style.display = 'flex';
  }
}

function initGame() {
  grid = newGrid();
  score = 0; lines = 0; level = 1; dropInterval = 1000;
  lastTime = 0; gameOver = false; paused = false;
  piece = null; nextPiece = null;
  document.getElementById('pauseOverlay').style.display = 'none';
  updateHUD();
  spawn();
}

let dropAccum = 0;

function loop(ts) {
  if (gameOver) return;
  const dt = ts - lastTime;
  lastTime = ts;
  dropAccum += dt;
  if (dropAccum >= dropInterval) {
    dropAccum = 0;
    if (!collides(piece, 0, 1)) {
      piece.y++;
    } else {
      lock(piece);
      clearLines();
      spawn();
    }
  }
  draw();
  animId = requestAnimationFrame(loop);
}

function startGame() {
  document.getElementById('overlay').style.display = 'none';
  initGame();
  lastTime = performance.now();
  animId = requestAnimationFrame(loop);
}

document.addEventListener('keydown', e => {
  if (!started || gameOver) {
    if (['ArrowLeft','ArrowRight','ArrowUp','ArrowDown',' '].includes(e.key) || e.key.length === 1) {
      started = true;
      startGame();
    }
    return;
  }

  if (e.key === 'p' || e.key === 'P') {
    paused = !paused;
    if (paused) {
      cancelAnimationFrame(animId);
      document.getElementById('pauseOverlay').style.display = 'flex';
    } else {
      document.getElementById('pauseOverlay').style.display = 'none';
      lastTime = performance.now();
      dropAccum = 0;
      animId = requestAnimationFrame(loop);
    }
    return;
  }

  if (paused || !piece) return;

  switch (e.key) {
    case 'ArrowLeft':
      if (!collides(piece, -1, 0)) piece.x--;
      break;
    case 'ArrowRight':
      if (!collides(piece, 1, 0)) piece.x++;
      break;
    case 'ArrowDown':
      if (!collides(piece, 0, 1)) { piece.y++; score++; updateHUD(); }
      else { lock(piece); clearLines(); spawn(); }
      dropAccum = 0;
      break;
    case 'ArrowUp': {
      const rot = rotate(piece.shape);
      if (!collides(piece, 0, 0, rot)) { piece.shape = rot; break; }
      if (!collides(piece, 1, 0, rot)) { piece.shape = rot; piece.x++; break; }
      if (!collides(piece, -1, 0, rot)) { piece.shape = rot; piece.x--; break; }
      break;
    }
    case ' ':
      e.preventDefault();
      while (!collides(piece, 0, 1)) { piece.y++; score += 2; }
      updateHUD();
      lock(piece); clearLines(); spawn();
      dropAccum = 0;
      break;
  }
  draw();
});

// show start overlay
document.getElementById('overlay').style.display = 'flex';
started = false;
draw();
